/**
 * Resolve a county name + state to its 5-digit FIPS code.
 * Handles common suffixes (County, Parish, Borough, etc.)
 */
export function resolveCountyFips(state: string, countyName: string): string | undefined {
  const normalized = countyName.toLowerCase()
    .replace(/\s+(county|parish|borough|census area|municipality|city and borough|city)$/i, '')
    .replace(/[.\']/g, '')
    .trim();
  return COUNTY_FIPS[state.toUpperCase()]?.[normalized];
}
